  1тЖТ"use client";
  2тЖТ
  3тЖТimport React, { useState, useMemo, useRef, useEffect, useCallback } from "react";
  4тЖТimport useSWR, { mutate } from "swr";
  5тЖТimport Link from "next/link";
  6тЖТimport { useRouter } from "next/navigation";
  7тЖТimport {
  8тЖТ  projects as projectsApi,
  9тЖТ  releases as releasesApi,
 10тЖТ  sources as sourcesApi,
 11тЖТ  semanticReleases as srApi,
 12тЖТ} from "@/lib/api/client";
 13тЖТimport { getProviderIcon } from "@/components/ui/provider-badge";
 14тЖТimport { ProjectLogo } from "@/components/ui/project-logo";
 15тЖТimport { timeAgo } from "@/lib/format";
 16тЖТimport { Plus, ArrowRight, LayoutGrid, List, Search, Pencil } from "lucide-react";
 17тЖТimport { SourceForm } from "@/components/sources/source-form";
 18тЖТimport { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
 19тЖТimport { ProjectForm } from "@/components/projects/project-form";
 20тЖТimport type { Project, Source } from "@/lib/api/types";
 21тЖТ
 22тЖТconst URGENCY_COLORS: Record<string, { bg: string; text: string }> = {
 23тЖТ  critical: { bg: "#dc2626", text: "#ffffff" },
 24тЖТ  high: { bg: "#f97316", text: "#ffffff" },
 25тЖТ  medium: { bg: "#f59e0b", text: "#ffffff" },
 26тЖТ  low: { bg: "#6b7280", text: "#ffffff" },
 27тЖТ};
 28тЖТ
 29тЖТ/* ---------- Project Card Logo ---------- */
 30тЖТ
 31тЖТfunction ProjectCardLogo({ projectId, name }: { projectId: string; name: string }) {
 32тЖТ  const { data } = useSWR(`project-${projectId}-card-sources`, () =>
 33тЖТ    sourcesApi.listByProject(projectId)
 34тЖТ  );
 35тЖТ  return <ProjectLogo name={name} sources={data?.data} size={40} />;
 36тЖТ}
 37тЖТ
 38тЖТ/* ---------- Overflow Flow ---------- */
 39тЖТ
 40тЖТconst LINE_HEIGHT = 28; // matches leading-7 (1.75rem = 28px)
 41тЖТconst MAX_LINES = 2;
 42тЖТconst MAX_HEIGHT = LINE_HEIGHT * MAX_LINES;
 43тЖТ
 44тЖТfunction FlowSection({
 45тЖТ  label,
 46тЖТ  moreHref,
 47тЖТ  children,
 48тЖТ}: {
 49тЖТ  label: string;
 50тЖТ  moreHref: string;
 51тЖТ  children: React.ReactNode;
 52тЖТ}) {
 53тЖТ  const measureRef = useRef<HTMLDivElement>(null);
 54тЖТ  const moreRef = useRef<HTMLSpanElement>(null);
 55тЖТ  const [visibleCount, setVisibleCount] = useState<number | null>(null);
 56тЖТ
 57тЖТ  const items = React.Children.toArray(children);
 58тЖТ
 59тЖТ  const measure = useCallback(() => {
 60тЖТ    const el = measureRef.current;
 61тЖТ    if (!el) return;
 62тЖТ    const nodes = el.children;
 63тЖТ    const itemNodeCount = nodes.length - 2; // exclude label (first) and hidden "moreтАж" span (last)
 64тЖТ    // Check if everything fits without overflow
 65тЖТ    if (el.scrollHeight <= MAX_HEIGHT + 4) {
 66тЖТ      setVisibleCount(items.length);
 67тЖТ      return;
 68тЖТ    }
 69тЖТ    // Measure actual "moreтАж" link width
 70тЖТ    const moreWidth = moreRef.current ? moreRef.current.offsetWidth + 8 : 52;
 71тЖТ    const containerWidth = el.offsetWidth;
 72тЖТ    // First pass: find all items that fit within MAX_HEIGHT (2 lines)
 73тЖТ    let lastFitting = 0;
 74тЖТ    for (let i = 1; i <= itemNodeCount; i++) {
 75тЖТ      const node = nodes[i] as HTMLElement;
 76тЖТ      if (node.offsetTop + node.offsetHeight > MAX_HEIGHT) break;
 77тЖТ      lastFitting = i;
 78тЖТ    }
 79тЖТ    // Second pass: walk backward from lastFitting until "moreтАж" fits after the item
 80тЖТ    let count = lastFitting;
 81тЖТ    while (count > 1) {
 82тЖТ      const node = nodes[count] as HTMLElement;
 83тЖТ      const nodeBottom = node.offsetTop + node.offsetHeight;
 84тЖТ      // If this item is on line 1, "moreтАж" can always wrap to line 2 тАФ we're fine
 85тЖТ      if (nodeBottom <= LINE_HEIGHT) break;
 86тЖТ      // Item is on line 2 тАФ check if "moreтАж" fits after it on the same line
 87тЖТ      const nodeRight = node.offsetLeft + node.offsetWidth;
 88тЖТ      if (nodeRight + moreWidth <= containerWidth) break;
 89тЖТ      count--;
 90тЖТ    }
 91тЖТ    setVisibleCount(Math.max(1, count));
 92тЖТ  }, [items.length]);
 93тЖТ
 94тЖТ  useEffect(() => {
 95тЖТ    measure();
 96тЖТ    const obs = new ResizeObserver(measure);
 97тЖТ    if (measureRef.current) obs.observe(measureRef.current);
 98тЖТ    return () => obs.disconnect();
 99тЖТ  }, [measure, items.length]);
100тЖТ
101тЖТ  const hasOverflow = visibleCount !== null && visibleCount < items.length;
102тЖТ  const displayed = visibleCount !== null ? items.slice(0, visibleCount) : items;
103тЖТ
104тЖТ  return (
105тЖТ    <div className="relative">
106тЖТ      {/* Hidden measurer тАФ renders all items to find cutoff */}
107тЖТ      <div
108тЖТ        ref={measureRef}
109тЖТ        className="text-[13px] leading-7"
110тЖТ        style={{ position: "absolute", visibility: "hidden", top: 0, left: 0, right: 0, pointerEvents: "none" }}
111тЖТ        aria-hidden="true"
112тЖТ      >
113тЖТ        <span className="text-[11px] font-medium uppercase tracking-[0.08em] mr-1.5">
114тЖТ          {label}:
115тЖТ        </span>
116тЖТ        {items}
117тЖТ        {/* Hidden "moreтАж" to measure its actual width */}
118тЖТ        <span ref={moreRef} className="inline-flex items-baseline text-[12px] font-medium whitespace-nowrap">
119тЖТ          moreтАж
120тЖТ        </span>
121тЖТ      </div>
122тЖТ      {/* Visible section */}
123тЖТ      <div className="text-[13px] leading-7">
124тЖТ        <span
125тЖТ          className="text-[11px] font-medium uppercase tracking-[0.08em] mr-1.5"
126тЖТ          style={{ color: "#9ca3af", fontFamily: "var(--font-dm-sans)" }}
127тЖТ        >
128тЖТ          {label}:
129тЖТ        </span>
130тЖТ        {displayed}
131тЖТ        {hasOverflow && (
132тЖТ          <Link
133тЖТ            href={moreHref}
134тЖТ            className="inline-flex items-baseline text-[12px] font-medium hover:underline whitespace-nowrap"
135тЖТ            style={{ color: "#e8601a" }}
136тЖТ          >
137тЖТ            moreтАж
138тЖТ          </Link>
139тЖТ        )}
140тЖТ      </div>
141тЖТ    </div>
142тЖТ  );
143тЖТ}
144тЖТ
145тЖТ/* ---------- Flow Card ---------- */
146тЖТ
147тЖТfunction ProjectFlowCard({ project }: { project: Project }) {
148тЖТ  const [sourceCreateOpen, setSourceCreateOpen] = useState(false);
149тЖТ  const [editingSource, setEditingSource] = useState<Source | null>(null);
150тЖТ
151тЖТ  const { data: srcData, mutate: mutateSources } = useSWR(
152тЖТ    `project-${project.id}-card-sources`,
153тЖТ    () => sourcesApi.listByProject(project.id),
154тЖТ  );
155тЖТ  const { data: relData } = useSWR(
156тЖТ    `project-${project.id}-card-releases`,
157тЖТ    () => releasesApi.listByProject(project.id, 1, 25),
158тЖТ  );
159тЖТ  const { data: srData } = useSWR(
160тЖТ    `project-${project.id}-card-sr`,
161тЖТ    () => srApi.list(project.id, 1, 10),
162тЖТ  );
163тЖТ
164тЖТ  const sources = srcData?.data ?? [];
165тЖТ  const releases = relData?.data ?? [];
166тЖТ  const srItems = srData?.data ?? [];
167тЖТ
168тЖТ  const sourceMap = useMemo(() => {
169тЖТ    const m = new Map<string, Source>();
170тЖТ    for (const s of sources) m.set(s.id, s);
171тЖТ    return m;
172тЖТ  }, [sources]);
173тЖТ
174тЖТ  return (
175тЖТ    <div
176тЖТ      className="rounded-md px-5 py-4"
177тЖТ      style={{ border: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
178тЖТ    >
179тЖТ      {/* Header */}
180тЖТ      <div className="flex items-center justify-between mb-2">
181тЖТ        <div className="flex items-center gap-3 min-w-0">
182тЖТ          <ProjectCardLogo projectId={project.id} name={project.name} />
183тЖТ          <div className="min-w-0">
184тЖТ            <Link
185тЖТ              href={`/projects/${project.id}`}
186тЖТ              className="group inline-flex items-center gap-1.5 text-[16px] font-bold transition-colors"
187тЖТ              style={{ fontFamily: "var(--font-fraunces)", color: "#e8601a" }}
188тЖТ            >
189тЖТ              {project.name}
190тЖТ              <ArrowRight className="h-3.5 w-3.5 opacity-0 -translate-x-1 transition-all group-hover:opacity-100 group-hover:translate-x-0" />
191тЖТ            </Link>
192тЖТ            {project.description && (
193тЖТ              <p
194тЖТ                className="text-[13px] truncate"
195тЖТ                style={{ color: "#6b7280", fontFamily: "var(--font-dm-sans)" }}
196тЖТ              >
197тЖТ                {project.description}
198тЖТ              </p>
199тЖТ            )}
200тЖТ          </div>
201тЖТ        </div>
202тЖТ      </div>
203тЖТ
204тЖТ      {/* Sources chips */}
205тЖТ      <div className="flex flex-wrap items-center gap-1.5 mb-3">
206тЖТ        <span
207тЖТ          className="text-[11px] font-medium uppercase tracking-[0.08em] mr-0.5"
208тЖТ          style={{ color: "#9ca3af", fontFamily: "var(--font-dm-sans)" }}
209тЖТ        >
210тЖТ          Sources:
211тЖТ        </span>
212тЖТ        {sources.map((source) => (
213тЖТ          <button
214тЖТ            key={source.id}
215тЖТ            onClick={() => setEditingSource(source)}
216тЖТ            className="group/chip inline-flex items-center gap-1.5 rounded px-2 py-0.5 text-[12px] transition-colors hover:bg-[#f0f0ee]"
217тЖТ            style={{
218тЖТ              backgroundColor: "#fafaf9",
219тЖТ              border: "1px solid #e8e8e5",
220тЖТ            }}
221тЖТ          >
222тЖТ            <span
223тЖТ              className="inline-block h-1.5 w-1.5 rounded-full shrink-0"
224тЖТ              style={{ backgroundColor: source.enabled ? "#16a34a" : "#d1d5db" }}
225тЖТ            />
226тЖТ            {(() => { const Icon = getProviderIcon(source.provider); return Icon ? <Icon size={12} className="shrink-0" style={{ color: "#9ca3af" }} /> : null; })()}
227тЖТ            <span style={{ fontFamily: "'JetBrains Mono', monospace", color: "#374151" }}>
228тЖТ              {source.repository}
229тЖТ            </span>
230тЖТ            {source.last_polled_at && (
231тЖТ              <span style={{ color: "#9ca3af" }}>
232тЖТ                {timeAgo(source.last_polled_at).replace(" ago", "")}
233тЖТ              </span>
234тЖТ            )}
235тЖТ            <Pencil className="h-2.5 w-2.5 hidden group-hover/chip:inline shrink-0" style={{ color: "#9ca3af", opacity: 0.5 }} />
236тЖТ          </button>
237тЖТ        ))}
238тЖТ        <button
239тЖТ          onClick={() => setSourceCreateOpen(true)}
240тЖТ          className="inline-flex items-center gap-1 px-2 py-0.5 text-[12px] font-medium rounded border transition-colors hover:bg-[#f3f3f1]"
241тЖТ          style={{
242тЖТ            borderColor: "#e8e8e5",
243тЖТ            color: "#9ca3af",
244тЖТ            fontFamily: "var(--font-dm-sans)",
245тЖТ          }}
246тЖТ        >
247тЖТ          <Plus className="h-3 w-3" />
248тЖТ          Add Source
249тЖТ        </button>
250тЖТ      </div>
251тЖТ
252тЖТ      {/* Releases flow */}
253тЖТ      {releases.length > 0 && (
254тЖТ        <FlowSection label="Releases" moreHref={`/releases?project=${project.id}`}>
255тЖТ          {releases.map((r) => {
256тЖТ            const src = sourceMap.get(r.source_id);
257тЖТ            return (
258тЖТ              <span key={r.id} className="inline-flex items-baseline mr-2.5">
259тЖТ                <Link
260тЖТ                  href={`/releases/${r.id}`}
261тЖТ                  className="text-[#2563eb] hover:underline"
262тЖТ                  style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: "12px" }}
263тЖТ                >
264тЖТ                  {r.version}
265тЖТ                </Link>
266тЖТ                {src && (
267тЖТ                  <span
268тЖТ                    className="text-[11px] ml-1 hidden sm:inline"
269тЖТ                    style={{ color: "#9ca3af" }}
270тЖТ                  >
271тЖТ                    ({src.repository.split("/").pop()})
272тЖТ                  </span>
273тЖТ                )}
274тЖТ                <span
275тЖТ                  className="text-[11px] ml-1"
276тЖТ                  style={{ color: "#c4c4c0" }}
277тЖТ                >
278тЖТ                  {timeAgo(r.released_at || r.created_at).replace(" ago", "")}
279тЖТ                </span>
280тЖТ              </span>
281тЖТ            );
282тЖТ          })}
283тЖТ        </FlowSection>
284тЖТ      )}
285тЖТ
286тЖТ      {/* Semantic releases */}
287тЖТ      {srItems.length > 0 && (
288тЖТ        <FlowSection label="Semantic Releases" moreHref={`/semantic-releases?project=${project.id}`}>
289тЖТ          {srItems.map((sr) => {
290тЖТ            const urgencyStyle = sr.report?.urgency
291тЖТ              ? URGENCY_COLORS[sr.report.urgency.toLowerCase()]
292тЖТ              : undefined;
293тЖТ            return (
294тЖТ              <span key={sr.id} className="inline-flex items-center gap-1.5 mr-2.5">
295тЖТ                <Link
296тЖТ                  href={`/projects/${project.id}/semantic-releases/${sr.id}`}
297тЖТ                  className="inline-flex items-center rounded px-1.5 py-0.5 text-[12px] leading-none hover:ring-1 hover:ring-blue-300 transition-shadow"
298тЖТ                  style={{
299тЖТ                    backgroundColor: "#eff6ff",
300тЖТ                    fontFamily: "'JetBrains Mono', monospace",
301тЖТ                    color: "#1d4ed8",
302тЖТ                  }}
303тЖТ                >
304тЖТ                  {sr.version}
305тЖТ                </Link>
306тЖТ                {urgencyStyle && (
307тЖТ                  <span
308тЖТ                    className="rounded px-1.5 py-0.5 text-[10px] uppercase font-bold tracking-wide leading-none"
309тЖТ                    style={{ backgroundColor: urgencyStyle.bg, color: urgencyStyle.text }}
310тЖТ                  >
311тЖТ                    {sr.report?.urgency}
312тЖТ                  </span>
313тЖТ                )}
314тЖТ              </span>
315тЖТ            );
316тЖТ          })}
317тЖТ        </FlowSection>
318тЖТ      )}
319тЖТ
320тЖТ      {/* Add Source dialog */}
321тЖТ      <Dialog open={sourceCreateOpen} onOpenChange={setSourceCreateOpen}>
322тЖТ        <DialogContent className="sm:max-w-lg">
323тЖТ          <DialogHeader>
324тЖТ            <DialogTitle>Add Source</DialogTitle>
325тЖТ          </DialogHeader>
326тЖТ          <SourceForm
327тЖТ            title="Add Source"
328тЖТ            projectId={project.id}
329тЖТ            onSubmit={async (input) => {
330тЖТ              const res = await sourcesApi.create(project.id, input);
331тЖТ              if (res.data?.id) sourcesApi.poll(res.data.id).catch(() => {});
332тЖТ            }}
333тЖТ            onSuccess={() => {
334тЖТ              setSourceCreateOpen(false);
335тЖТ              mutateSources();
336тЖТ            }}
337тЖТ            onCancel={() => setSourceCreateOpen(false)}
338тЖТ          />
339тЖТ        </DialogContent>
340тЖТ      </Dialog>
341тЖТ
342тЖТ      {/* Edit Source dialog */}
343тЖТ      <Dialog
344тЖТ        open={!!editingSource}
345тЖТ        onOpenChange={(open) => { if (!open) setEditingSource(null); }}
346тЖТ      >
347тЖТ        <DialogContent className="sm:max-w-lg">
348тЖТ          <DialogHeader>
349тЖТ            <DialogTitle>Edit Source</DialogTitle>
350тЖТ          </DialogHeader>
351тЖТ          {editingSource && (
352тЖТ            <SourceForm
353тЖТ              key={editingSource.id}
354тЖТ              title="Edit Source"
355тЖТ              initial={editingSource}
356тЖТ              onSubmit={async (input) => {
357тЖТ                await sourcesApi.update(editingSource.id, input);
358тЖТ              }}
359тЖТ              onSuccess={() => {
360тЖТ                setEditingSource(null);
361тЖТ                mutateSources();
362тЖТ              }}
363тЖТ              onCancel={() => setEditingSource(null)}
364тЖТ            />
365тЖТ          )}
366тЖТ        </DialogContent>
367тЖТ      </Dialog>
368тЖТ    </div>
369тЖТ  );
370тЖТ}
371тЖТ
372тЖТ/* ---------- Compact Row ---------- */
373тЖТ
374тЖТfunction ProjectCompactRow({ project }: { project: Project }) {
375тЖТ  const router = useRouter();
376тЖТ  const { data: relData } = useSWR(`project-${project.id}-card-releases`, () =>
377тЖТ    releasesApi.listByProject(project.id, 1, 5)
378тЖТ  );
379тЖТ  const { data: srcData } = useSWR(`project-${project.id}-card-sources`, () =>
380тЖТ    sourcesApi.listByProject(project.id)
381тЖТ  );
382тЖТ  const { data: srData } = useSWR(`project-${project.id}-card-sr`, () =>
383тЖТ    srApi.list(project.id, 1, 3)
384тЖТ  );
385тЖТ
386тЖТ  const releases = relData?.data ?? [];
387тЖТ  const sources = srcData?.data ?? [];
388тЖТ  const srItems = srData?.data ?? [];
389тЖТ  const latest = releases[0];
390тЖТ  const latestSr = srItems[0];
391тЖТ
392тЖТ  const sourceMap = useMemo(() => {
393тЖТ    const m = new Map<string, Source>();
394тЖТ    for (const s of sources) m.set(s.id, s);
395тЖТ    return m;
396тЖТ  }, [sources]);
397тЖТ
398тЖТ  const latestSrc = latest ? sourceMap.get(latest.source_id) : undefined;
399тЖТ  const latestIcon = latestSrc ? getProviderIcon(latestSrc.provider) : undefined;
400тЖТ
401тЖТ  const urgencyStyle = latestSr?.report?.urgency
402тЖТ    ? URGENCY_COLORS[latestSr.report.urgency.toLowerCase()]
403тЖТ    : undefined;
404тЖТ
405тЖТ  return (
406тЖТ    <div
407тЖТ      onClick={() => router.push(`/projects/${project.id}`)}
408тЖТ      className="flex items-center gap-4 rounded-md px-4 py-2.5 transition-colors hover:bg-[#f9f9f7] cursor-pointer"
409тЖТ      style={{ border: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
410тЖТ    >
411тЖТ      {/* Project name */}
412тЖТ      <span
413тЖТ        className="flex items-center gap-2 text-[14px] font-bold shrink-0"
414тЖТ        style={{ fontFamily: "var(--font-fraunces)", color: "#e8601a", minWidth: "160px" }}
415тЖТ      >
416тЖТ        <ProjectLogo name={project.name} sources={sources} size={24} />
417тЖТ        {project.name}
418тЖТ      </span>
419тЖТ
420тЖТ      {/* Latest release */}
421тЖТ      <span className="flex items-center gap-1.5 shrink-0" style={{ minWidth: "140px" }}>
422тЖТ        {latest ? (
423тЖТ          <>
424тЖТ            <Link
425тЖТ              href={`/releases/${latest.id}`}
426тЖТ              onClick={(e) => e.stopPropagation()}
427тЖТ              className="inline-flex items-center rounded px-1.5 py-0.5 text-[12px] leading-none hover:ring-1 hover:ring-gray-300 transition-shadow"
428тЖТ              style={{
429тЖТ                backgroundColor: "#f3f3f1",
430тЖТ                fontFamily: "'JetBrains Mono', monospace",
431тЖТ                color: "#374151",
432тЖТ              }}
433тЖТ            >
434тЖТ              {latest.version}
435тЖТ            </Link>
436тЖТ            {latestIcon && latestIcon({ size: 12, className: "shrink-0", style: { color: "#9ca3af" } })}
437тЖТ          </>
438тЖТ        ) : (
439тЖТ          <span className="text-[12px] italic" style={{ color: "#c4c4c0" }}>
440тЖТ            No releases
441тЖТ          </span>
442тЖТ        )}
443тЖТ      </span>
444тЖТ
445тЖТ      {/* Latest semantic release */}
446тЖТ      <span className="flex items-center gap-1.5 flex-1 min-w-0">
447тЖТ        {latestSr ? (
448тЖТ          <>
449тЖТ            <Link
450тЖТ              href={`/projects/${project.id}/semantic-releases/${latestSr.id}`}
451тЖТ              onClick={(e) => e.stopPropagation()}
452тЖТ              className="inline-flex items-center rounded px-1.5 py-0.5 text-[12px] leading-none shrink-0 hover:ring-1 hover:ring-blue-300 transition-shadow"
453тЖТ              style={{
454тЖТ                backgroundColor: "#eff6ff",
455тЖТ                fontFamily: "'JetBrains Mono', monospace",
456тЖТ                color: "#1d4ed8",
457тЖТ              }}
458тЖТ            >
459тЖТ              {latestSr.version}
460тЖТ            </Link>
461тЖТ            {urgencyStyle && (
462тЖТ              <span
463тЖТ                className="inline-flex items-center rounded-full px-1.5 py-0.5 text-[10px] font-medium leading-none shrink-0"
464тЖТ                style={{ backgroundColor: urgencyStyle.bg, color: urgencyStyle.text }}
465тЖТ              >
466тЖТ                {latestSr.report?.urgency}
467тЖТ              </span>
468тЖТ            )}
469тЖТ            {latestSr.report?.summary && (
470тЖТ              <span className="text-[11px] truncate" style={{ color: "#9ca3af" }}>
471тЖТ                {latestSr.report.summary.length > 60
472тЖТ                  ? latestSr.report.summary.slice(0, 60) + "\u2026"
473тЖТ                  : latestSr.report.summary}
474тЖТ              </span>
475тЖТ            )}
476тЖТ          </>
