 12тЖТ// ProjectsStore defines the persistence operations for projects.
 13тЖТtype ProjectsStore interface {
 14тЖТ	ListProjects(ctx context.Context, page, perPage int) ([]models.Project, int, error)
 15тЖТ	CreateProject(ctx context.Context, p *models.Project) error
 16тЖТ	GetProject(ctx context.Context, id string) (*models.Project, error)
 17тЖТ	UpdateProject(ctx context.Context, id string, p *models.Project) error
 18тЖТ	DeleteProject(ctx context.Context, id string) error
 19тЖТ}
 20тЖТ
 21тЖТ// ProjectsHandler implements HTTP handlers for the /projects resource.
 22тЖТtype ProjectsHandler struct {
 23тЖТ	store ProjectsStore
 24тЖТ}
 25тЖТ
 26тЖТ// NewProjectsHandler returns a new ProjectsHandler.
 27тЖТfunc NewProjectsHandler(store ProjectsStore) *ProjectsHandler {
 28тЖТ	return &ProjectsHandler{store: store}
 29тЖТ}
 30тЖТ
 31тЖТ// List handles GET /projects тАФ returns a paginated list of projects.
 32тЖТfunc (h *ProjectsHandler) List(w http.ResponseWriter, r *http.Request) {
 33тЖТ	page, perPage := ParsePagination(r)
 34тЖТ	projects, total, err := h.store.ListProjects(r.Context(), page, perPage)
 35тЖТ	if err != nil {
 36тЖТ		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to list projects")
 37тЖТ		return
 38тЖТ	}
 39тЖТ	// Return empty array, not null, when no results.
 40тЖТ	if projects == nil {
 41тЖТ		projects = []models.Project{}
 42тЖТ	}
 43тЖТ	RespondList(w, r, http.StatusOK, projects, page, perPage, total)
 44тЖТ}
 45тЖТ
 46тЖТ// Create handles POST /projects тАФ creates a new project.
 47тЖТfunc (h *ProjectsHandler) Create(w http.ResponseWriter, r *http.Request) {
 48тЖТ	var p models.Project
 49тЖТ	if err := DecodeJSON(r, &p); err != nil {
 50тЖТ		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid JSON body")
 51тЖТ		return
 52тЖТ	}
 53тЖТ	p.Name = strings.TrimSpace(p.Name)
 54тЖТ	if p.Name == "" {
 55тЖТ		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "Name is required")
 56тЖТ		return
 57тЖТ	}
 58тЖТ	// Default agent_rules to empty object if not provided.
 59тЖТ	if p.AgentRules == nil {
 60тЖТ		p.AgentRules = json.RawMessage(`{}`)
 61тЖТ	}
 62тЖТ	if err := h.store.CreateProject(r.Context(), &p); err != nil {
 63тЖТ		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to create project")
 64тЖТ		return
 65тЖТ	}
 66тЖТ	RespondJSON(w, r, http.StatusCreated, p)
 67тЖТ}
 68тЖТ
 69тЖТ// Get handles GET /projects/{id} тАФ returns a single project.
 70тЖТfunc (h *ProjectsHandler) Get(w http.ResponseWriter, r *http.Request) {
 71тЖТ	id := r.PathValue("id")
 72тЖТ	if id == "" {
 73тЖТ		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid project ID")
 74тЖТ		return
 75тЖТ	}
 76тЖТ	p, err := h.store.GetProject(r.Context(), id)
 77тЖТ	if err != nil {
 78тЖТ		RespondError(w, r, http.StatusNotFound, "not_found", "Project not found")
 79тЖТ		return
 80тЖТ	}
 81тЖТ	RespondJSON(w, r, http.StatusOK, p)
 82тЖТ}
 83тЖТ
 84тЖТ// Update handles PUT /projects/{id} тАФ updates an existing project.
 85тЖТfunc (h *ProjectsHandler) Update(w http.ResponseWriter, r *http.Request) {
 86тЖТ	id := r.PathValue("id")
 87тЖТ	if id == "" {
 88тЖТ		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid project ID")
 89тЖТ		return
 90тЖТ	}
 91тЖТ	var p models.Project
 92тЖТ	if err := DecodeJSON(r, &p); err != nil {
 93тЖТ		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid JSON body")
 94тЖТ		return
 95тЖТ	}
 96тЖТ	p.Name = strings.TrimSpace(p.Name)
 97тЖТ	if p.Name == "" {
 98тЖТ		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "Name is required")
 99тЖТ		return
100тЖТ	}
101тЖТ	if p.AgentRules == nil {
102тЖТ		p.AgentRules = json.RawMessage(`{}`)
103тЖТ	}
104тЖТ	if err := h.store.UpdateProject(r.Context(), id, &p); err != nil {
105тЖТ		RespondError(w, r, http.StatusNotFound, "not_found", "Project not found")
106тЖТ		return
107тЖТ	}
108тЖТ	p.ID = id
109тЖТ	RespondJSON(w, r, http.StatusOK, p)
110тЖТ}
111тЖТ
112тЖТ// Delete handles DELETE /projects/{id} тАФ deletes a project.
113тЖТfunc (h *ProjectsHandler) Delete(w http.ResponseWriter, r *http.Request) {
114тЖТ	id := r.PathValue("id")
115тЖТ	if id == "" {
116тЖТ		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid project ID")
117тЖТ		return
118тЖТ	}
119тЖТ	if err := h.store.DeleteProject(r.Context(), id); err != nil {
120тЖТ		RespondError(w, r, http.StatusNotFound, "not_found", "Project not found")
121тЖТ		return
122тЖТ	}
123тЖТ	w.WriteHeader(http.StatusNoContent)
124тЖТ}
