 37тЖТfunc (s *PgStore) ListProjects(ctx context.Context, page, perPage int) ([]models.Project, int, error) {
 38тЖТ	var total int
 39тЖТ	err := s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM projects`).Scan(&total)
 40тЖТ	if err != nil {
 41тЖТ		return nil, 0, fmt.Errorf("count projects: %w", err)
 42тЖТ	}
 43тЖТ	offset := (page - 1) * perPage
 44тЖТ	rows, err := s.pool.Query(ctx,
 45тЖТ		`SELECT id, name, COALESCE(description,''), COALESCE(agent_prompt,''),
 46тЖТ		        COALESCE(agent_rules,'{}'), created_at, updated_at
 47тЖТ		 FROM projects ORDER BY created_at DESC LIMIT $1 OFFSET $2`, perPage, offset)
 48тЖТ	if err != nil {
 49тЖТ		return nil, 0, fmt.Errorf("list projects: %w", err)
 50тЖТ	}
 51тЖТ	defer rows.Close()
 52тЖТ	var projects []models.Project
 53тЖТ	for rows.Next() {
 54тЖТ		var p models.Project
 55тЖТ		if err := rows.Scan(&p.ID, &p.Name, &p.Description, &p.AgentPrompt, &p.AgentRules, &p.CreatedAt, &p.UpdatedAt); err != nil {
 56тЖТ			return nil, 0, fmt.Errorf("scan project: %w", err)
 57тЖТ		}
 58тЖТ		projects = append(projects, p)
 59тЖТ	}
 60тЖТ	return projects, total, nil
 61тЖТ}
 62тЖТ
 63тЖТfunc (s *PgStore) CreateProject(ctx context.Context, p *models.Project) error {
 64тЖТ	return s.pool.QueryRow(ctx,
 65тЖТ		`INSERT INTO projects (name, description, agent_prompt, agent_rules)
 66тЖТ		 VALUES ($1, $2, $3, $4)
 67тЖТ		 RETURNING id, created_at, updated_at`,
 68тЖТ		p.Name, p.Description, p.AgentPrompt, p.AgentRules,
 69тЖТ	).Scan(&p.ID, &p.CreatedAt, &p.UpdatedAt)
 70тЖТ}
 71тЖТ
 72тЖТfunc (s *PgStore) GetProject(ctx context.Context, id string) (*models.Project, error) {
 73тЖТ	var p models.Project
 74тЖТ	err := s.pool.QueryRow(ctx,
 75тЖТ		`SELECT id, name, COALESCE(description,''), COALESCE(agent_prompt,''),
 76тЖТ		        COALESCE(agent_rules,'{}'), created_at, updated_at
 77тЖТ		 FROM projects WHERE id = $1`, id,
 78тЖТ	).Scan(&p.ID, &p.Name, &p.Description, &p.AgentPrompt, &p.AgentRules, &p.CreatedAt, &p.UpdatedAt)
 79тЖТ	if err != nil {
 80тЖТ		return nil, err
 81тЖТ	}
 82тЖТ	return &p, nil
 83тЖТ}
 84тЖТ
 85тЖТfunc (s *PgStore) UpdateProject(ctx context.Context, id string, p *models.Project) error {
 86тЖТ	return s.pool.QueryRow(ctx,
 87тЖТ		`UPDATE projects SET name=$1, description=$2, agent_prompt=$3, agent_rules=$4, updated_at=NOW()
 88тЖТ		 WHERE id=$5 RETURNING updated_at`,
 89тЖТ		p.Name, p.Description, p.AgentPrompt, p.AgentRules, id,
 90тЖТ	).Scan(&p.UpdatedAt)
 91тЖТ}
 92тЖТ
 93тЖТfunc (s *PgStore) DeleteProject(ctx context.Context, id string) error {
 94тЖТ	tag, err := s.pool.Exec(ctx, `DELETE FROM projects WHERE id = $1`, id)
 95тЖТ	if err != nil {
 96тЖТ		return err
 97тЖТ	}
 98тЖТ	if tag.RowsAffected() == 0 {
 99тЖТ		return fmt.Errorf("not found")
100тЖТ	}
101тЖТ	return nil
102тЖТ}
