108тЖТ	keyHash := hex.EncodeToString(hash[:])
109тЖТ	var exists bool
110тЖТ	err := s.pool.QueryRow(ctx,
111тЖТ		`SELECT EXISTS(SELECT 1 FROM api_keys WHERE key_hash = $1)`, keyHash,
112тЖТ	).Scan(&exists)
113тЖТ	return exists, err
114тЖТ}
