 37тЖТ
 38тЖТ/* ---------- Overflow Flow ---------- */
 39тЖТ
 40тЖТconst LINE_HEIGHT = 28; // matches leading-7 (1.75rem = 28px)
 41тЖТconst MAX_LINES = 2;
 42тЖТconst MAX_HEIGHT = LINE_HEIGHT * MAX_LINES;
 43тЖТ
 44тЖТfunction FlowSection({
 45тЖТ  label,
 46тЖТ  moreHref,
 47тЖТ  children,
 48тЖТ}: {
 49тЖТ  label: string;
 50тЖТ  moreHref: string;
 51тЖТ  children: React.ReactNode;
 52тЖТ}) {
 53тЖТ  const measureRef = useRef<HTMLDivElement>(null);
 54тЖТ  const moreRef = useRef<HTMLSpanElement>(null);
 55тЖТ  const [visibleCount, setVisibleCount] = useState<number | null>(null);
 56тЖТ
 57тЖТ  const items = React.Children.toArray(children);
 58тЖТ
 59тЖТ  const measure = useCallback(() => {
 60тЖТ    const el = measureRef.current;
 61тЖТ    if (!el) return;
 62тЖТ    const nodes = el.children;
 63тЖТ    const itemNodeCount = nodes.length - 2; // exclude label (first) and hidden "moreтАж" span (last)
 64тЖТ    // Check if everything fits without overflow
 65тЖТ    if (el.scrollHeight <= MAX_HEIGHT + 4) {
 66тЖТ      setVisibleCount(items.length);
 67тЖТ      return;
 68тЖТ    }
 69тЖТ    // Measure actual "moreтАж" link width
 70тЖТ    const moreWidth = moreRef.current ? moreRef.current.offsetWidth + 8 : 52;
 71тЖТ    const containerWidth = el.offsetWidth;
 72тЖТ    // First pass: find all items that fit within MAX_HEIGHT (2 lines)
 73тЖТ    let lastFitting = 0;
 74тЖТ    for (let i = 1; i <= itemNodeCount; i++) {
 75тЖТ      const node = nodes[i] as HTMLElement;
 76тЖТ      if (node.offsetTop + node.offsetHeight > MAX_HEIGHT) break;
 77тЖТ      lastFitting = i;
 78тЖТ    }
 79тЖТ    // Second pass: walk backward from lastFitting until "moreтАж" fits after the item
 80тЖТ    let count = lastFitting;
 81тЖТ    while (count > 1) {
 82тЖТ      const node = nodes[count] as HTMLElement;
 83тЖТ      const nodeBottom = node.offsetTop + node.offsetHeight;
 84тЖТ      // If this item is on line 1, "moreтАж" can always wrap to line 2 тАФ we're fine
 85тЖТ      if (nodeBottom <= LINE_HEIGHT) break;
 86тЖТ      // Item is on line 2 тАФ check if "moreтАж" fits after it on the same line
 87тЖТ      const nodeRight = node.offsetLeft + node.offsetWidth;
 88тЖТ      if (nodeRight + moreWidth <= containerWidth) break;
 89тЖТ      count--;
 90тЖТ    }
 91тЖТ    setVisibleCount(Math.max(1, count));
 92тЖТ  }, [items.length]);
 93тЖТ
 94тЖТ  useEffect(() => {
 95тЖТ    measure();
 96тЖТ    const obs = new ResizeObserver(measure);
 97тЖТ    if (measureRef.current) obs.observe(measureRef.current);
 98тЖТ    return () => obs.disconnect();
 99тЖТ  }, [measure, items.length]);
100тЖТ
101тЖТ  const hasOverflow = visibleCount !== null && visibleCount < items.length;
102тЖТ  const displayed = visibleCount !== null ? items.slice(0, visibleCount) : items;
103тЖТ
104тЖТ  return (
105тЖТ    <div className="relative">
106тЖТ      {/* Hidden measurer тАФ renders all items to find cutoff */}
107тЖТ      <div
108тЖТ        ref={measureRef}
109тЖТ        className="text-[13px] leading-7"
110тЖТ        style={{ position: "absolute", visibility: "hidden", top: 0, left: 0, right: 0, pointerEvents: "none" }}
111тЖТ        aria-hidden="true"
112тЖТ      >
113тЖТ        <span className="text-[11px] font-medium uppercase tracking-[0.08em] mr-1.5">
114тЖТ          {label}:
115тЖТ        </span>
116тЖТ        {items}
117тЖТ        {/* Hidden "moreтАж" to measure its actual width */}
118тЖТ        <span ref={moreRef} className="inline-flex items-baseline text-[12px] font-medium whitespace-nowrap">
119тЖТ          moreтАж
120тЖТ        </span>
121тЖТ      </div>
122тЖТ      {/* Visible section */}
123тЖТ      <div className="text-[13px] leading-7">
124тЖТ        <span
125тЖТ          className="text-[11px] font-medium uppercase tracking-[0.08em] mr-1.5"
126тЖТ          style={{ color: "#9ca3af", fontFamily: "var(--font-dm-sans)" }}
127тЖТ        >
128тЖТ          {label}:
129тЖТ        </span>
130тЖТ        {displayed}
131тЖТ        {hasOverflow && (
132тЖТ          <Link
133тЖТ            href={moreHref}
134тЖТ            className="inline-flex items-baseline text-[12px] font-medium hover:underline whitespace-nowrap"
135тЖТ            style={{ color: "#e8601a" }}
136тЖТ          >
137тЖТ            moreтАж
138тЖТ          </Link>
139тЖТ        )}
140тЖТ      </div>
141тЖТ    </div>
142тЖТ  );
143тЖТ}
